INSERT OR IGNORE INTO posts (id, bbsid, board_id, user_id, title, content, content_text, signature, posted_at, reply_count, source_file, wayback_ts) VALUES (294, 156794, 7, 235, '无题闲话', '每当寂寞的时候就想起故乡的深林,还有童年的梦,那一片片带有神秘色彩的林海世界,什么时候在能回到故乡,希望能愿自己一个美梦,那就是找一片原始深林开个牧场,放着牛，羊,鸡,鸭,在养一只猎犬,扛一把猎枪慢步在丛林中,过着神仙般的生活,不用都市中的生活而烦恼,多么美好的事情,时常抱怨自己为什么会想来到城市里,原本属于林区中的主人却放弃奔向都市,明天忙碌着,呼吸着污染的空气,走在车水马龙的街头,现在又开始羡慕北方的山村生活了,没有来过繁华城市的时候以为是一件多么羡慕的事情,其实不然,还是丛林生活比较安全可靠,没有世俗烦恼.如果有这一天我一定要去实现这一切,现在就这样慢慢的等待,等待着........', '每当寂寞的时候就想起故乡的深林,还有童年的梦,那一片片带有神秘色彩的林海世界,什么时候在能回到故乡,希望能愿自己一个美梦,那就是找一片原始深林开个牧场,放着牛，羊,鸡,鸭,在养一只猎犬,扛一把猎枪慢步在丛林中,过着神仙般的生活,不用都市中的生活而烦恼,多么美好的事情,时常抱怨自己为什么会想来到城市里,原本属于林区中的主人却放弃奔向都市,明天忙碌着,呼吸着污染的空气,走在车水马龙的街头,现在又开始羡慕北方的山村生活了,没有来过繁华城市的时候以为是一件多么羡慕的事情,其实不然,还是丛林生活比较安全可靠,没有世俗烦恼.如果有这一天我一定要去实现这一切,现在就这样慢慢的等待,等待着........', NULL, '2002-04-06 10:13:00', 1, '20020424032158_bbsid_156794_board_7_e279271bfc.html', '20020424032158');
